import{_ as o,o as e,c as n,a2 as i}from"./chunks/framework.CuteRReP.js";const g=JSON.parse('{"title":"cm-how-it-work","description":"Complete guide to vibe coding with the Cody Master skill kit — from idea to deploy. Covers the full workflow, skills used at each phase, and common use cases. R","frontmatter":{"title":"cm-how-it-work","description":"Complete guide to vibe coding with the Cody Master skill kit — from idea to deploy. Covers the full workflow, skills used at each phase, and common use cases. R","keywords":["cm-how-it-work","cody master","ai skill"],"robots":"index, follow"},"headers":[],"relativePath":"skills/cm-how-it-work.md","filePath":"skills/cm-how-it-work.md"}'),a={name:"skills/cm-how-it-work.md"};function c(l,t,d,r,h,s){return e(),n("div",null,[...t[0]||(t[0]=[i('<blockquote><p><strong>📋 Full Skill Source</strong> — This is the complete, unedited SKILL.md file. Nothing is hidden or summarized.</p></blockquote><p><a href="./">← Back to Skills Library</a></p><h1 id="cody-master-kit-—-the-ultimate-vibe-coding-guide" tabindex="-1">Cody Master Kit — The Ultimate Vibe Coding Guide <a class="header-anchor" href="#cody-master-kit-—-the-ultimate-vibe-coding-guide" aria-label="Permalink to &quot;Cody Master Kit — The Ultimate Vibe Coding Guide&quot;">​</a></h1><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Bộ kit <strong>Cody Master (CM)</strong> biến ý tưởng thành production code thông qua 13 skill chuyên biệt đã được tối ưu hóa. Quy trình này đảm bảo chất lượng cao nhất, bảo mật tuyệt đối và tốc độ thực thi tối đa.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>💡 Ý tưởng → 📐 Thiết kế → 🧪 Test-first (TDD) → 💻 Code → ✅ Verify → 🚀 Deploy → 🔄 Iterate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="quy-trinh-lam-viec-workflow" tabindex="-1">Quy trình Làm việc (Workflow) <a class="header-anchor" href="#quy-trinh-lam-viec-workflow" aria-label="Permalink to &quot;Quy trình Làm việc (Workflow)&quot;">​</a></h2><h3 id="phase-0-identity-safety-🔒" tabindex="-1">Phase 0: Identity &amp; Safety 🔒 <a class="header-anchor" href="#phase-0-identity-safety-🔒" aria-label="Permalink to &quot;Phase 0: Identity &amp; Safety 🔒&quot;">​</a></h3><blockquote><p><strong>Rule số 1:</strong> Luôn xác nhận danh tính trước khi thực hiện bất kỳ hành động nào có thể thay đổi trạng thái project.</p></blockquote><ul><li><strong>Skill:</strong> <code>cm-identity-guard</code></li><li><strong>Khi nào:</strong> Bắt đầu phiên làm việc, trước khi git push, deploy, hoặc thao tác database.</li><li><strong>Hành động:</strong> Chạy <code>node check-identity.js</code> (hoặc script tương tự) để verify GitHub/Cloudflare/Supabase accounts.</li></ul><hr><h3 id="phase-1-planning-design-📐" tabindex="-1">Phase 1: Planning &amp; Design 📐 <a class="header-anchor" href="#phase-1-planning-design-📐" aria-label="Permalink to &quot;Phase 1: Planning &amp; Design 📐&quot;">​</a></h3><blockquote><p><strong>Hiểu rõ &#39;Job to be Done&#39; (JTBD) và kiến trúc trước khi viết code.</strong></p></blockquote><ul><li><strong>Skill:</strong> <code>cm-planning</code> (Gộp từ brainstorming + writing-plans)</li><li><strong>Hành động:</strong><ol><li>Brainstorm yêu cầu và phân tích i18n.</li><li>Đề xuất architecture và tech stack.</li><li>Viết <code>implementation_plan.md</code> chi tiết.</li></ol></li><li><strong>Output:</strong> Tài liệu thiết kế và kế hoạch thực thi đã được user approve.</li></ul><hr><h3 id="phase-2-implementation-tdd-execution-💻" tabindex="-1">Phase 2: Implementation (TDD &amp; Execution) 💻 <a class="header-anchor" href="#phase-2-implementation-tdd-execution-💻" aria-label="Permalink to &quot;Phase 2: Implementation (TDD &amp; Execution) 💻&quot;">​</a></h3><blockquote><p><strong>Biến kế hoạch thành mã nguồn thực tế một cách an toàn.</strong></p></blockquote><ul><li><strong>Skills:</strong><ul><li><code>cm-tdd</code>: Chu kỳ Red-Green-Refactor. Không viết code production nếu không có test fail trước.</li><li><code>cm-execution</code>: Thực thi plan một cách thông minh (Manual, Parallel, hoặc Subagent mode).</li><li><code>cm-project-bootstrap</code>: Cho dự án mới — setup repo, i18n, SEO, và deploy pipeline từ Day 0.</li><li><code>cm-git-worktrees</code>: Cách ly các đầu việc khác nhau để không lẫn lộn state.</li></ul></li></ul><hr><h3 id="phase-3-quality-control-verification-✅" tabindex="-1">Phase 3: Quality Control &amp; Verification ✅ <a class="header-anchor" href="#phase-3-quality-control-verification-✅" aria-label="Permalink to &quot;Phase 3: Quality Control &amp; Verification ✅&quot;">​</a></h3><blockquote><p><strong>Chứng minh bằng bằng chứng (Evidence), không phải bằng lời nói.</strong></p></blockquote><ul><li><strong>Skills:</strong><ul><li><code>cm-quality-gate</code>: Setup hạ tầng test (<code>test:gate</code>) và verify output trước khi claim &quot;xong&quot;.</li><li><code>cm-debugging</code>: Khi test fail, dùng framework systematic investigation để tìm root cause.</li><li><code>cm-code-review</code>: Quy trình request và nhận feedback chuyên nghiệp.</li></ul></li></ul><hr><h3 id="phase-4-safe-deployment-🚀" tabindex="-1">Phase 4: Safe Deployment 🚀 <a class="header-anchor" href="#phase-4-safe-deployment-🚀" aria-label="Permalink to &quot;Phase 4: Safe Deployment 🚀&quot;">​</a></h3><blockquote><p><strong>Ship code mà không lo sợ sự cố.</strong></p></blockquote><ul><li><strong>Skills:</strong><ul><li><code>cm-safe-deploy</code>: Chạy 8-gate pipeline (Secret → Syntax → Test → Build → Deploy → Smoke).</li><li><code>cm-safe-i18n</code>: Dịch và đồng bộ hóa ngôn ngữ đồng nhất trên toàn bộ project.</li><li><code>cm-terminal</code>: Giám sát mọi câu lệnh terminal để phát hiện lỗi ngay lập tức.</li></ul></li></ul><hr><h2 id="cody-master-kit-—-tom-tat-13-skills" tabindex="-1">Cody Master Kit — Tóm tắt 13 Skills <a class="header-anchor" href="#cody-master-kit-—-tom-tat-13-skills" aria-label="Permalink to &quot;Cody Master Kit — Tóm tắt 13 Skills&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Skill</th><th>Chức năng chính</th></tr></thead><tbody><tr><td>1</td><td><code>cm-project-bootstrap</code></td><td>Khởi tạo dự án chuẩn 10-phase.</td></tr><tr><td>2</td><td><code>cm-planning</code></td><td>Khám phá ý tưởng và lập kế hoạch thực thi.</td></tr><tr><td>3</td><td><code>cm-execution</code></td><td>Chạy implementation plan (Manual/Parallel/Subagent).</td></tr><tr><td>4</td><td><code>cm-tdd</code></td><td>Quy trình Test-Driven Development nghiêm ngặt.</td></tr><tr><td>5</td><td><code>cm-quality-gate</code></td><td>Setup test files + Verification trước khi claim/deploy.</td></tr><tr><td>6</td><td><code>cm-code-review</code></td><td>Quản lý vòng đời PR và feedback.</td></tr><tr><td>7</td><td><code>cm-safe-deploy</code></td><td>8-gate automated deployment pipeline.</td></tr><tr><td>8</td><td><code>cm-safe-i18n</code></td><td>Quản lý và dịch đa ngôn ngữ an toàn.</td></tr><tr><td>9</td><td><code>cm-debugging</code></td><td>Điều tra lỗi có hệ thống (Root cause first).</td></tr><tr><td>10</td><td><code>cm-terminal</code></td><td>Protocol chạy lệnh terminal an toàn.</td></tr><tr><td>11</td><td><code>cm-git-worktrees</code></td><td>Cách ly môi trường code theo task.</td></tr><tr><td>12</td><td><code>cm-skill-mastery</code></td><td>Tìm kiếm, cài đặt và viết skill mới.</td></tr><tr><td>13</td><td><code>cm-identity-guard</code></td><td>Bảo vệ project khỏi deploy nhầm account/project.</td></tr></tbody></table><h2 id="🚀-he-thong-tu-chu-autonomous-workflow" tabindex="-1">🚀 Hệ Thống Tự Chủ (Autonomous Workflow) <a class="header-anchor" href="#🚀-he-thong-tu-chu-autonomous-workflow" aria-label="Permalink to &quot;🚀 Hệ Thống Tự Chủ (Autonomous Workflow)&quot;">​</a></h2><p>Bộ kit hỗ trợ chế độ tự chạy (Autonomous Mode) bằng cách áp dụng vòng lặp <strong>Reason → Act → Reflect → Verify (RARV)</strong>.</p><h3 id="cach-su-dung-workflow" tabindex="-1">Cách sử dụng Workflow: <a class="header-anchor" href="#cach-su-dung-workflow" aria-label="Permalink to &quot;Cách sử dụng Workflow:&quot;">​</a></h3><ol><li><strong><code>/cm-start [mục tiêu]</code></strong>: Bắt đầu công việc. Hệ thống sẽ tự tạo <code>cm-tasks.json</code>, chia nhỏ task, bật giao diện theo dõi, và tự động dùng các skill CM để hoàn thành.</li><li><strong><code>/cm-dashboard</code></strong>: Mở Dashboard theo dõi trực quan trên trình duyệt (thấy được Kanban board, log luồng suy nghĩ, và tiến độ).</li><li><strong><code>/cm-status</code></strong>: Xem tóm tắt tiến độ nhanh trong Terminal.</li></ol><hr><h2 id="💡-huong-dan-kich-hoat-theo-use-cases" tabindex="-1">💡 Hướng Dẫn Kích Hoạt Theo Use Cases <a class="header-anchor" href="#💡-huong-dan-kich-hoat-theo-use-cases" aria-label="Permalink to &quot;💡 Hướng Dẫn Kích Hoạt Theo Use Cases&quot;">​</a></h2><p>Có 2 cách dùng Cody Master: <strong>Tự chủ hoàn toàn (Via Workflows)</strong> hoặc <strong>Kích hoạt thủ công từng skill (Via Prompting)</strong>.</p><h3 id="_1-xay-dung-tinh-nang-moi-du-an-moi-tu-chu" tabindex="-1">1. Xây dựng Tính năng Mới / Dự án Mới (Tự Chủ) <a class="header-anchor" href="#_1-xay-dung-tinh-nang-moi-du-an-moi-tu-chu" aria-label="Permalink to &quot;1. Xây dựng Tính năng Mới / Dự án Mới (Tự Chủ)&quot;">​</a></h3><blockquote><p>Cách tốt nhất để giao việc trọn gói.</p></blockquote><ul><li><strong>Lệnh:</strong> <code>/cm-start &quot;Build tính năng quản lý user gồm màn hình list và CRUD form&quot;</code></li><li><strong>Luồng ngầm định:</strong> Planning → tạo Task JSON → sub-agents liên tục chạy <code>cm-tdd</code> và <code>cm-quality-gate</code> cho từng task đến khi xong.</li></ul><h3 id="_2-sua-loi-production-thu-cong" tabindex="-1">2. Sửa Lỗi Production (Thủ công) <a class="header-anchor" href="#_2-sua-loi-production-thu-cong" aria-label="Permalink to &quot;2. Sửa Lỗi Production (Thủ công)&quot;">​</a></h3><blockquote><p>Bug cần sự giám sát chặt chẽ và không nên cho AI tự mò mẫm đổi code quá nhiều.</p></blockquote><ul><li><strong>Bước 1:</strong> Kích hoạt <code>cm-debugging</code> để tìm Root Cause.</li><li><strong>Bước 2:</strong> Kích hoạt <code>cm-tdd</code> để viết test reproduce bug và sửa nó.</li><li><strong>Bước 3:</strong> Kích hoạt <code>cm-safe-deploy</code> để ship code an toàn.</li></ul><h3 id="_3-setup-project-moi-tu-đau" tabindex="-1">3. Setup Project Mới Từ Đầu <a class="header-anchor" href="#_3-setup-project-moi-tu-đau" aria-label="Permalink to &quot;3. Setup Project Mới Từ Đầu&quot;">​</a></h3><blockquote><p>Thiết lập nền tảng để tránh nợ kỹ thuật sau này.</p></blockquote><ul><li><strong>Lệnh gõ:</strong> &quot;Sử dụng <code>cm-identity-guard</code> đảm bảo đúng account, sau đó chạy <code>cm-project-bootstrap</code> để setup dự án Next.js mới.&quot;</li></ul><h3 id="_4-dich-thuat-đa-ngon-ngu-hang-loat" tabindex="-1">4. Dịch thuật Đa Ngôn Ngữ Hàng Loạt <a class="header-anchor" href="#_4-dich-thuat-đa-ngon-ngu-hang-loat" aria-label="Permalink to &quot;4. Dịch thuật Đa Ngôn Ngữ Hàng Loạt&quot;">​</a></h3><blockquote><p>Công việc nhàm chán nhưng dễ sai sót nếu AI mất tập trung.</p></blockquote><ul><li><strong>Lệnh gõ:</strong> &quot;Sử dụng <code>cm-safe-i18n</code> để extract toàn bộ text cứng trong thư mục <code>/components</code> ra file <code>vi.json</code> và <code>en.json</code>.&quot;</li></ul><hr><h2 id="_8-quy-tac-vang-golden-rules" tabindex="-1">8 Quy Tắc Vàng (Golden Rules) <a class="header-anchor" href="#_8-quy-tac-vang-golden-rules" aria-label="Permalink to &quot;8 Quy Tắc Vàng (Golden Rules)&quot;">​</a></h2><ol><li><strong>Identity First:</strong> Verify account (<code>cm-identity-guard</code>) trước khi push/deploy.</li><li><strong>Design Before Code:</strong> Luôn có plan được duyệt trước khi gõ phím.</li><li><strong>i18n Day 0:</strong> Luôn quan tâm đa ngôn ngữ ngay từ bước brainstorm.</li><li><strong>Test Before Code:</strong> RED → GREEN → REFACTOR. Không có ngoại lệ.</li><li><strong>Evidence Over Claims:</strong> Chỉ tin output của terminal/test results, không tin AI &quot;nói&quot; đã xong.</li><li><strong>Deploy via Gates:</strong> 8 gates phải pass tuần tự. Bất kỳ gate nào fail = DỪNG.</li><li><strong>Safe Secrets:</strong> Không bao giờ commit secrets. Dùng <code>.dev.vars</code> hoặc quản lý qua Cloudflare.</li><li><strong>Parallel Power:</strong> Sử dụng execution parallel cho i18n hoặc multi-bug fixes.</li></ol>',52)])])}const m=o(a,[["render",c]]);export{g as __pageData,m as default};
